from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest
import time
import os

app = Flask(__name__)

# Security: Read from environment variables
METRICS_PASSWORD = os.environ.get('METRICS_PASSWORD', 'default_secure_password')
ALLOWED_IPS = os.environ.get('ALLOWED_IPS', '127.0.0.1').split(',')

# Metrics
REQUEST_COUNT = Counter('app_requests_total', 'Total requests', ['method', 'endpoint', 'status'])
REQUEST_LATENCY = Histogram('app_request_duration_seconds', 'Request latency')
ACTIVE_REQUESTS = Gauge('app_active_requests', 'Active requests')

# Business metrics
BUSINESS_EVENTS = Counter('app_business_events_total', 'Business events', ['event_type'])

def validate_request():
    # IP whitelist check
    client_ip = request.remote_addr
    if client_ip not in ALLOWED_IPS:
        return False
    
    # Basic authentication check
    auth = request.authorization
    if not auth or auth.password != METRICS_PASSWORD:
        return False
    
    return True

@app.before_request
def start_timer():
    request.start_time = time.time()
    ACTIVE_REQUESTS.inc()

@app.after_request
def record_metrics(response):
    ACTIVE_REQUESTS.dec()
    
    # Record request latency
    latency = time.time() - request.start_time
    REQUEST_LATENCY.observe(latency)
    
    # Record request count
    REQUEST_COUNT.labels(
        method=request.method,
        endpoint=request.endpoint or 'unknown',
        status=response.status_code
    ).inc()
    
    return response

@app.route('/metrics')
def metrics():
    if not validate_request():
        return 'Unauthorized', 401
    
    # Generate and return metrics
    metrics_data = generate_latest()
    return metrics_data, 200, {'Content-Type': 'text/plain; version=0.0.4'}

@app.route('/health')
def health():
    return jsonify({'status': 'healthy'}), 200

@app.route('/business-event/<event_type>')
def business_event(event_type):
    BUSINESS_EVENTS.labels(event_type=event_type).inc()
    return jsonify({'status': 'event recorded'}), 200

@app.route('/protected')
def protected():
    return jsonify({'message': 'This is a protected endpoint'}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)